import { NgModule } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule, Routes } from '@angular/router';

import { APCComponent } from './apc/apc.component';
import { ARTComponent } from './art/art.component';
import { BRBComponent } from './brb/brb.component';
import { BSPComponent } from './bsp/bsp.component';
import { CSPComponent } from './csp/csp.component';
import { EAGComponent } from './eag/eag.component';


const routes: Routes = [{
  path: 'apc',
  component: APCComponent
}, {
  path: 'art',
  component: ARTComponent
}, {
  path: 'brb',
  component: BRBComponent
}, {
  path: 'bsp',
  component: BSPComponent
}, {
  path: 'csp',
  component: CSPComponent
}, {
  path: 'eag',
  component: EAGComponent
}];

@NgModule({
  declarations: [],
  imports: [
    CommonModule,
    RouterModule.forChild(routes)
  ],
  exports: [RouterModule]
})
export class BRPRoutingModule { }
